import{_ as a,o as l,c as t,ag as i}from"./chunks/framework.BqfgOMAh.js";const p=JSON.parse('{"title":"NexusFlow 0.2.0 Beta","description":"","frontmatter":{},"headers":[],"relativePath":"zh/releases/0.2.0.md","filePath":"zh/releases/0.2.0.md"}'),r={name:"zh/releases/0.2.0.md"};function o(n,e,s,d,h,u){return l(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="nexusflow-0-2-0-beta" tabindex="-1">NexusFlow 0.2.0 Beta <a class="header-anchor" href="#nexusflow-0-2-0-beta" aria-label="Permalink to &quot;NexusFlow 0.2.0 Beta&quot;">​</a></h1><p>0.2.0 是 0.1.0 之后的第一个 Beta 更新，重点是把 NexusFlow 从“桌面 AI 蓝图助手”扩展为“可被外部 IDE / Agent 接入的 UE 自动化网关”，同时继续提升蓝图操作稳定性，并引入可试用的 Widget Blueprint 能力。</p><h2 id="亮点" tabindex="-1">亮点 <a class="header-anchor" href="#亮点" aria-label="Permalink to &quot;亮点&quot;">​</a></h2><h3 id="内置-mcp-server" tabindex="-1">内置 MCP Server <a class="header-anchor" href="#内置-mcp-server" aria-label="Permalink to &quot;内置 MCP Server&quot;">​</a></h3><p>NexusFlow 桌面主程序现在可以作为 MCP Server 运行。支持 MCP 的 IDE 或 Agent 可以连接 NexusFlow，使用 UE 上下文、Skill 搜索、Knowledge 加载、Blueprint 动作执行、节点搜索、模板搜索和编辑器命令等能力。</p><h3 id="nexusflow-skill" tabindex="-1">NexusFlow Skill <a class="header-anchor" href="#nexusflow-skill" aria-label="Permalink to &quot;NexusFlow Skill&quot;">​</a></h3><p>新增 <code>nexusflow-skill</code>，提供 AGENTS、Claude Code 和 Cursor 的便携入口，让外部 Agent 知道如何安全使用 NexusFlow MCP 工具。</p><h3 id="blueprint-skill-稳定性提升" tabindex="-1">Blueprint Skill 稳定性提升 <a class="header-anchor" href="#blueprint-skill-稳定性提升" aria-label="Permalink to &quot;Blueprint Skill 稳定性提升&quot;">​</a></h3><p>蓝图读取、生成、增量 patch、编译验证和错误恢复流程得到大量修补。对复杂图、变量、组件、接口、动态 pin 和特殊节点的处理更可靠。</p><h3 id="widget-skill-mvp" tabindex="-1">Widget Skill MVP <a class="header-anchor" href="#widget-skill-mvp" aria-label="Permalink to &quot;Widget Skill MVP&quot;">​</a></h3><p>新增实验性的 Widget Skill，可创建和修改 UMG Widget Blueprint，支持 Widget Tree 读写、属性级 patch、分支重写和真实预览截图。</p><h3 id="更适合-agent-的搜索工作流" tabindex="-1">更适合 Agent 的搜索工作流 <a class="header-anchor" href="#更适合-agent-的搜索工作流" aria-label="Permalink to &quot;更适合 Agent 的搜索工作流&quot;">​</a></h3><p>Blueprint 模板搜索、模板加载和节点搜索已作为 MCP 工具暴露，便于 Agent 在构造蓝图逻辑前先发现可复用模式和正确节点。</p><h3 id="api-key-环境变量引用" tabindex="-1">API Key 环境变量引用 <a class="header-anchor" href="#api-key-环境变量引用" aria-label="Permalink to &quot;API Key 环境变量引用&quot;">​</a></h3><p>模型配置现在支持在 API Key 字段填写 <code>${OPENAI_API_KEY}</code> 这类环境变量引用。真实密钥由 Tauri 后端在运行时读取，配置中只保存变量名引用，适合不想把明文 API Key 写入应用配置的用户。</p><h3 id="全局-llm-代理" tabindex="-1">全局 LLM 代理 <a class="header-anchor" href="#全局-llm-代理" aria-label="Permalink to &quot;全局 LLM 代理&quot;">​</a></h3><p>设置中心新增独立的「LLM 代理」页面，可为所有 LLM 请求统一配置 HTTP / HTTPS / SOCKS4 / SOCKS5 代理。代理密码使用加密密钥存储保存；该代理只作用于 LLM 请求，不影响 UE、Bridge、MCP 或窗口内部通信。</p><h2 id="升级建议" tabindex="-1">升级建议 <a class="header-anchor" href="#升级建议" aria-label="Permalink to &quot;升级建议&quot;">​</a></h2><ul><li>如果你只使用 NexusFlow 桌面聊天窗口，可以照常升级。</li><li>如果你希望避免在应用配置中保存真实 API Key，可以在模型配置的 API Key 字段填写 <code>${ENV_NAME}</code>，例如 <code>${OPENAI_API_KEY}</code>。</li><li>如果你的网络环境访问 LLM 服务需要代理，可以在设置 → LLM 代理中配置全局代理；若本地代理软件启用了分流/绕过规则，请确保目标 LLM 服务被设置为强制代理。</li><li>如果你使用 Cursor、Claude Code 或自定义 Agent，建议阅读 <a href="./../guide/mcp">在 IDE / Agent 中使用 NexusFlow</a> 和 <a href="./../guide/agent-skill">NexusFlow Skill</a>。</li><li>Widget Skill 仍为实验性能力，建议从小型 UI 或可回滚资产开始试用。</li></ul>',19)])])}const P=a(r,[["render",o]]);export{p as __pageData,P as default};
